1	/**
2	 * SIGNAL News Trading Terminal — Frontend Application
3	 * Auto-refreshing financial news aggregator with sentiment analysis
4	 */
5	
6	"use strict";
7	
8	import SignalAuth from './auth.js';
9	
10	// ---------------------------------------------------------------------------
11	// Config
12	// ---------------------------------------------------------------------------
13	
14	const API = "/api";
15	const DEFAULT_LIMIT = 200;
16	const NEW_THRESHOLD_MS = 60000; // 60 seconds
17	
18	// ---------------------------------------------------------------------------
19	// State
20	// ---------------------------------------------------------------------------
21	
22	let state = {
23	  items: [],
24	  seenIds: new Set(),
25	  newIds: new Set(),
26	  sources: [],
27	  stats: null,
28	  filter: {
29	    sentiment: "all",
30	    sources: new Set(), // empty = all selected
31	    query: "",
32	    dateFrom: "",
33	    dateTo: "",
34	    hideDuplicates: false,
35	  },
36	  refreshInterval: 5000,
37	  refreshTimer: null,
38	  lastRefresh: null,
39	  connected: false,
40	  loading: true,
41	  totalFetched: 0,
42	  fetchCount: 0,
43	  itemsPerSecond: 0,
44	  startTime: Date.now(),
45	  sidebarOpen: false,
46	  modalOpen: false,
47	  soundEnabled: false,
48	};
49	
50	// ---------------------------------------------------------------------------
51	// DOM References
52	// ---------------------------------------------------------------------------
53	
54	const $ = (sel) => document.querySelector(sel);
55	const $$ = (sel) => [...document.querySelectorAll(sel)];
56	
57	// ---------------------------------------------------------------------------
58	// Utilities
59	// ---------------------------------------------------------------------------
60	
61	function formatTime(dateStr) {
62	  if (!dateStr) return "--:--:--";
63	  try {
64	    const d = new Date(dateStr);
65	    if (isNaN(d.getTime())) return "--:--:--";
66	    return d.toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
67	  } catch {
68	    return "--:--:--";
69	  }
70	}
71	
72	function formatDate(dateStr) {
73	  if (!dateStr) return "";
74	  try {
75	    const d = new Date(dateStr);
76	    if (isNaN(d.getTime())) return "";
77	    return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
78	  } catch {
79	    return "";
80	  }
81	}
82	
83	function timeAgo(dateStr) {
84	  if (!dateStr) return "";
85	  try {
86	    const d = new Date(dateStr);
87	    const now = new Date();
88	    const diff = now - d;
89	    if (diff < 0) return "just now";
90	    if (diff < 60000) return `${Math.floor(diff / 1000)}s ago`;
91	    if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
92	    if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
93	    return `${Math.floor(diff / 86400000)}d ago`;
94	  } catch {
95	    return "";
96	  }
97	}
98	
99	function isNew(dateStr) {
100	  if (!dateStr) return false;
101	  try {
102	    const d = new Date(dateStr);
103	    return (Date.now() - d.getTime()) < NEW_THRESHOLD_MS;
104	  } catch {
105	    return false;
106	  }
107	}
108	
109	function escapeHtml(str) {
110	  const div = document.createElement("div");
111	  div.textContent = str;
112	  return div.innerHTML;
113	}
114	
115	function truncate(str, max) {
116	  if (!str) return "";
117	  return str.length > max ? str.slice(0, max) + "\u2026" : str;
118	}
119	
120	// ---------------------------------------------------------------------------
121	// API Calls
122	// ---------------------------------------------------------------------------
123	
124	async function fetchNews() {
125	  try {
126	    const params = new URLSearchParams({ limit: DEFAULT_LIMIT });
127	    if (state.filter.dateFrom) params.set("from", state.filter.dateFrom);
128	    if (state.filter.dateTo) params.set("to", state.filter.dateTo);
129	    const res = await SignalAuth.fetch(`${API}/news?${params}`);
130	    if (!res.ok) throw new Error(`HTTP ${res.status}`);
131	    const data = await res.json();
132	    state.connected = true;
133	    state.loading = false;
134	    state.fetchCount++;
135	    state.lastRefresh = new Date().toISOString();
136	
137	    if (data.items && data.items.length > 0) {
138	      // Detect new items
139	      const newIds = new Set();
140	      for (const item of data.items) {
141	        if (!state.seenIds.has(item.id)) {
142	          newIds.add(item.id);
143	          state.seenIds.add(item.id);
144	        }
145	      }
146	
147	      // Play sound for new items if enabled
148	      if (state.soundEnabled && newIds.size > 0 && state.fetchCount > 1) {
149	        playNotificationSound();
150	      }
151	
152	      state.newIds = newIds;
153	      state.items = data.items;
154	      state.totalFetched = data.count;
155	
156	      // Calculate items/second
157	      const elapsed = (Date.now() - state.startTime) / 1000;
158	      state.itemsPerSecond = elapsed > 0 ? (state.totalFetched / elapsed).toFixed(1) : 0;
159	    }
160	
161	    renderNews();
162	    updateStatusBar();
163	    updateConnectionStatus(true);
164	  } catch (err) {
165	    state.connected = false;
166	    state.loading = false;
167	    updateConnectionStatus(false);
168	    if (state.items.length === 0) {
169	      renderEmpty("Unable to connect to API. Retrying...");
170	    }
171	  }
172	}
173	
174	async function fetchSources() {
175	  try {
176	    const res = await SignalAuth.fetch(`${API}/sources`);
177	    if (!res.ok) return;
178	    const data = await res.json();
179	    state.sources = data.sources || [];
180	    renderSources();
181	  } catch {
182	    // silent
183	  }
184	}
185	
186	async function fetchStats() {
187	  try {
188	    const res = await SignalAuth.fetch(`${API}/stats`);
189	    if (!res.ok) return;
190	    state.stats = await res.json();
191	    updateHeaderStats();
192	  } catch {
193	    // silent
194	  }
195	}
196	
197	async function forceRefresh() {
198	  try {
199	    const btn = $("#btn-refresh");
200	    if (btn) {
201	      btn.disabled = true;
202	      btn.innerHTML = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" class="spinning"><path d="M21 12a9 9 0 11-6.219-8.56"/></svg>Refreshing`;
203	    }
204	    await SignalAuth.fetch(`${API}/refresh`, { method: "POST" });
205	    await fetchNews();
206	    await fetchStats();
207	    if (btn) {
208	      btn.disabled = false;
209	      btn.innerHTML = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12a9 9 0 11-6.219-8.56"/><path d="M22 3v6h-6"/></svg>Refresh`;
210	    }
211	  } catch {
212	    const btn = $("#btn-refresh");
213	    if (btn) {
214	      btn.disabled = false;
215	      btn.innerHTML = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12a9 9 0 11-6.219-8.56"/><path d="M22 3v6h-6"/></svg>Refresh`;
216	    }
217	  }
218	}
219	
220	// ---------------------------------------------------------------------------
221	// Sound
222	// ---------------------------------------------------------------------------
223	
224	function playNotificationSound() {
225	  try {
226	    const ctx = new (window.AudioContext || window.webkitAudioContext)();
227	    const osc = ctx.createOscillator();
228	    const gain = ctx.createGain();
229	    osc.connect(gain);
230	    gain.connect(ctx.destination);
231	    osc.type = "sine";
232	    osc.frequency.setValueAtTime(880, ctx.currentTime);
233	    osc.frequency.setValueAtTime(1100, ctx.currentTime + 0.05);
234	    gain.gain.setValueAtTime(0.08, ctx.currentTime);
235	    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.15);
236	    osc.start(ctx.currentTime);
237	    osc.stop(ctx.currentTime + 0.15);
238	  } catch {
239	    // silent
240	  }
241	}
242	
243	// ---------------------------------------------------------------------------
244	// Filtering
245	// ---------------------------------------------------------------------------
246	
247	function getFilteredItems() {
248	  return state.items.filter((item) => {
249	    // Sentiment filter
250	    if (state.filter.sentiment !== "all" && item.sentiment_label !== state.filter.sentiment) {
251	      return false;
252	    }
253	    // Source filter
254	    if (state.filter.sources.size > 0 && !state.filter.sources.has(item.source)) {
255	      return false;
256	    }
257	    // Query filter
258	    if (state.filter.query) {
259	      const q = state.filter.query.toLowerCase();
260	      const inTitle = (item.title || "").toLowerCase().includes(q);
261	      const inSummary = (item.summary || "").toLowerCase().includes(q);
262	      if (!inTitle && !inSummary) return false;
263	    }
264	    // Duplicate filter
265	    if (state.filter.hideDuplicates && item.duplicate) {
266	      return false;
267	    }
268	    return true;
269	  });
270	}
271	
272	function getSentimentCounts() {
273	  const counts = { all: 0, bullish: 0, bearish: 0, neutral: 0 };
274	  for (const item of state.items) {
275	    counts.all++;
276	    if (counts[item.sentiment_label] !== undefined) {
277	      counts[item.sentiment_label]++;
278	    }
279	  }
280	  return counts;
281	}
282	
283	// ---------------------------------------------------------------------------
284	// Rendering
285	// ---------------------------------------------------------------------------
286	
287	function renderNews() {
288	  const container = $("#news-body");
289	  if (!container) return;
290	
291	  const items = getFilteredItems();
292	
293	  if (items.length === 0 && !state.loading) {
294	    container.innerHTML = `
295	      <tr>
296	        <td colspan="5">
297	          <div class="empty-state">
298	            <div class="icon">\u25C7</div>
299	            <div>No items match current filters</div>
300	            <div style="font-size:11px">Try adjusting sentiment or source filters</div>
301	          </div>
302	        </td>
303	      </tr>`;
304	    return;
305	  }
306	
307	  const rows = items.map((item) => {
308	    const isNewItem = state.newIds.has(item.id);
309	    const isFresh = isNew(item.fetched_at);
310	    const rowClass = isNewItem ? "news-row-new" : "";
311	    const pubTime = formatTime(item.published);
312	    const ago = timeAgo(item.published);
313	    const dupBadge = item.duplicate ? '<span class="badge-dup">DUP</span>' : '';
314	
315	    return `<tr class="${rowClass}" data-id="${item.id}">
316	      <td class="cell-time" title="${ago}">${pubTime}</td>
317	      <td><span class="sentiment-badge ${item.sentiment_label}"><span class="sentiment-dot"></span>${item.sentiment_label}</span></td>
318	      <td><span class="source-tag">${escapeHtml(item.source || "")}</span></td>
319	      <td class="cell-headline">
320	        <a href="${escapeHtml(item.link || "#")}" target="_blank" rel="noopener noreferrer">${escapeHtml(item.title || "Untitled")}</a>${isFresh ? '<span class="badge-new">NEW</span>' : ''}${dupBadge}
321	      </td>
322	      <td class="cell-summary">${escapeHtml(truncate(item.summary, 120))}</td>
323	    </tr>`;
324	  });
325	
326	  container.innerHTML = rows.join("");
327	  updateSentimentFilters();
328	  updateItemCount();
329	}
330	
331	function renderSkeleton() {
332	  const container = $("#news-body");
333	  if (!container) return;
334	  const rows = Array.from({ length: 15 }, (_, i) => {
335	    const w1 = 50 + Math.random() * 20;
336	    const w2 = 200 + Math.random() * 200;
337	    const w3 = 100 + Math.random() * 100;
338	    return `<tr class="skeleton-row">
339	      <td><div class="skeleton-block" style="width:${w1}px"></div></td>
340	      <td><div class="skeleton-block" style="width:60px"></div></td>
341	      <td><div class="skeleton-block" style="width:80px"></div></td>
342	      <td><div class="skeleton-block" style="width:${w2}px"></div></td>
343	      <td><div class="skeleton-block" style="width:${w3}px"></div></td>
344	    </tr>`;
345	  });
346	  container.innerHTML = rows.join("");
347	}
348	
349	function renderEmpty(message) {
350	  const container = $("#news-body");
351	  if (!container) return;
352	  container.innerHTML = `
353	    <tr>
354	      <td colspan="5">
355	        <div class="loading-state">
356	          <div class="loading-spinner"></div>
357	          <div>${escapeHtml(message)}</div>
358	        </div>
359	      </td>
360	    </tr>`;
361	}
362	
363	function renderSources() {
364	  const container = $("#source-list");
365	  if (!container) return;
366	
367	  if (!state.sources.length) {
368	    // Show all feed names from a static list
369	    const feedNames = [
370	      "CNBC", "CNBC_World", "Reuters_Business", "MarketWatch", "MarketWatch_Markets",
371	      "Investing_com", "Yahoo_Finance", "Nasdaq", "SeekingAlpha", "Benzinga",
372	      "AP_News", "Bloomberg_Business", "Bloomberg_Markets",
373	      "BBC_Business", "Google_News_Business"
374	    ];
375	    container.innerHTML = feedNames.map((name) => `
376	      <label class="source-item">
377	        <input type="checkbox" checked data-source="${name}">
378	        <span>${name.replace(/_/g, " ")}</span>
379	        <span class="source-count">--</span>
380	      </label>`).join("");
381	  } else {
382	    container.innerHTML = state.sources.map((s) => `
383	      <label class="source-item">
384	        <input type="checkbox" checked data-source="${s.name}">
385	        <span>${s.name.replace(/_/g, " ")}</span>
386	        <span class="source-count">${s.total_items}</span>
387	      </label>`).join("");
388	  }
389	
390	  // Bind change events
391	  container.querySelectorAll('input[type="checkbox"]').forEach((cb) => {
392	    cb.addEventListener("change", () => {
393	      updateSourceFilter();
394	      renderNews();
395	    });
396	  });
397	}
398	
399	function updateSourceFilter() {
400	  const unchecked = new Set();
401	  const allChecked = [];
402	  $$('#source-list input[type="checkbox"]').forEach((cb) => {
403	    if (!cb.checked) {
404	      unchecked.add(cb.dataset.source);
405	    } else {
406	      allChecked.push(cb.dataset.source);
407	    }
408	  });
409	  // If all are checked, sources is empty (meaning "all")
410	  if (unchecked.size === 0) {
411	    state.filter.sources = new Set();
412	  } else {
413	    state.filter.sources = new Set(allChecked);
414	  }
415	}
416	
417	function updateSentimentFilters() {
418	  const counts = getSentimentCounts();
419	  const countEls = {
420	    all: $("#sentiment-count-all"),
421	    bullish: $("#sentiment-count-bullish"),
422	    bearish: $("#sentiment-count-bearish"),
423	    neutral: $("#sentiment-count-neutral"),
424	  };
425	  Object.entries(countEls).forEach(([key, el]) => {
426	    if (el) el.textContent = counts[key] || 0;
427	  });
428	}
429	
430	function updateItemCount() {
431	  const el = $("#total-items");
432	  if (el) {
433	    const filtered = getFilteredItems();
434	    el.textContent = filtered.length;
435	  }
436	}
437	
438	function updateHeaderStats() {
439	  if (!state.stats) return;
440	  const el = $("#total-items");
441	  if (el && state.filter.sentiment === "all" && state.filter.sources.size === 0 && !state.filter.query) {
442	    el.textContent = state.stats.total_items;
443	  }
444	  const feedCountEl = $("#feed-count");
445	  if (feedCountEl) feedCountEl.textContent = state.stats.feed_count;
446	  const avgSentEl = $("#avg-sentiment");
447	  if (avgSentEl) {
448	    const score = state.stats.avg_sentiment_score;
449	    avgSentEl.textContent = (score >= 0 ? "+" : "") + score.toFixed(3);
450	    avgSentEl.style.color = score > 0.05 ? "var(--green)" : score < -0.05 ? "var(--red)" : "var(--yellow)";
451	  }
452	}
453	
454	function updateConnectionStatus(connected) {
455	  const dot = $("#connection-dot");
456	  const label = $("#connection-label");
457	  if (dot) {
458	    dot.className = connected ? "status-dot connected" : "status-dot disconnected";
459	  }
460	  if (label) {
461	    label.textContent = connected ? "LIVE" : "DISCONNECTED";
462	  }
463	}
464	
465	function updateStatusBar() {
466	  const lastRefreshEl = $("#last-refresh");
467	  if (lastRefreshEl && state.lastRefresh) {
468	    lastRefreshEl.textContent = formatTime(state.lastRefresh);
469	  }
470	  const ipsEl = $("#items-per-sec");
471	  if (ipsEl) {
472	    ipsEl.textContent = state.itemsPerSecond;
473	  }
474	}
475	
476	// ---------------------------------------------------------------------------
477	// Clock
478	// ---------------------------------------------------------------------------
479	
480	function updateClock() {
481	  const el = $("#clock");
482	  if (!el) return;
483	  const now = new Date();
484	  const time = now.toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
485	  const date = now.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric", year: "numeric" });
486	  el.textContent = `${date}  ${time}`;
487	}
488	
489	// ---------------------------------------------------------------------------
490	// Auto-refresh
491	// ---------------------------------------------------------------------------
492	
493	function startAutoRefresh() {
494	  stopAutoRefresh();
495	  state.refreshTimer = setInterval(() => {
496	    fetchNews();
497	  }, state.refreshInterval);
498	}
499	
500	function stopAutoRefresh() {
501	  if (state.refreshTimer) {
502	    clearInterval(state.refreshTimer);
503	    state.refreshTimer = null;
504	  }
505	}
506	
507	// ---------------------------------------------------------------------------
508	// Event Handlers
509	// ---------------------------------------------------------------------------
510	
511	function bindEvents() {
512	  // Sentiment filter buttons
513	  $$(".sentiment-filter-btn").forEach((btn) => {
514	    btn.addEventListener("click", () => {
515	      const value = btn.dataset.sentiment;
516	      state.filter.sentiment = value;
517	      $$(".sentiment-filter-btn").forEach((b) => b.classList.remove("active"));
518	      btn.classList.add("active");
519	      renderNews();
520	    });
521	  });
522	
523	  // Search input
524	  const searchInput = $("#search-input");
525	  if (searchInput) {
526	    let debounceTimer;
527	    searchInput.addEventListener("input", (e) => {
528	      clearTimeout(debounceTimer);
529	      debounceTimer = setTimeout(() => {
530	        state.filter.query = e.target.value.trim();
531	        renderNews();
532	      }, 150);
533	    });
534	  }
535	
536	  // Date range inputs
537	  const dateFrom = $("#date-from");
538	  const dateTo = $("#date-to");
539	  if (dateFrom) {
540	    dateFrom.addEventListener("change", (e) => {
541	      state.filter.dateFrom = e.target.value;
542	      fetchNews();
543	    });
544	  }
545	  if (dateTo) {
546	    dateTo.addEventListener("change", (e) => {
547	      state.filter.dateTo = e.target.value;
548	      fetchNews();
549	    });
550	  }
551	  const clearDateBtn = $("#btn-clear-dates");
552	  if (clearDateBtn) {
553	    clearDateBtn.addEventListener("click", () => {
554	      state.filter.dateFrom = "";
555	      state.filter.dateTo = "";
556	      if (dateFrom) dateFrom.value = "";
557	      if (dateTo) dateTo.value = "";
558	      fetchNews();
559	    });
560	  }
561	
562	  // Hide duplicates toggle
563	  const hideDupsCb = $("#hide-duplicates");
564	  if (hideDupsCb) {
565	    hideDupsCb.addEventListener("change", (e) => {
566	      state.filter.hideDuplicates = e.target.checked;
567	      renderNews();
568	    });
569	  }
570	
571	  // Refresh button
572	  const refreshBtn = $("#btn-refresh");
573	  if (refreshBtn) {
574	    refreshBtn.addEventListener("click", forceRefresh);
575	  }
576	
577	  // Refresh interval selector
578	  const intervalSelect = $("#refresh-interval");
579	  if (intervalSelect) {
580	    intervalSelect.addEventListener("change", (e) => {
581	      state.refreshInterval = parseInt(e.target.value, 10);
582	      startAutoRefresh();
583	    });
584	  }
585	
586	  // API docs button
587	  const docsBtn = $("#btn-docs");
588	  if (docsBtn) {
589	    docsBtn.addEventListener("click", () => toggleModal(true));
590	  }
591	
592	  // Modal close
593	  const modalClose = $("#modal-close");
594	  if (modalClose) {
595	    modalClose.addEventListener("click", () => toggleModal(false));
596	  }
597	
598	  const modalOverlay = $("#modal-overlay");
599	  if (modalOverlay) {
600	    modalOverlay.addEventListener("click", (e) => {
601	      if (e.target === modalOverlay) toggleModal(false);
602	    });
603	  }
604	
605	  // Sound toggle
606	  const soundBtn = $("#btn-sound");
607	  if (soundBtn) {
608	    soundBtn.addEventListener("click", () => {
609	      state.soundEnabled = !state.soundEnabled;
610	      soundBtn.classList.toggle("active", state.soundEnabled);
611	      soundBtn.title = state.soundEnabled ? "Sound alerts ON" : "Sound alerts OFF";
612	      const icon = soundBtn.querySelector(".sound-icon");
613	      if (icon) {
614	        icon.innerHTML = state.soundEnabled
615	          ? '<path d="M11 5L6 9H2v6h4l5 4V5z"/><path d="M19.07 4.93a10 10 0 010 14.14M15.54 8.46a5 5 0 010 7.07"/>'
616	          : '<path d="M11 5L6 9H2v6h4l5 4V5z"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/>';
617	      }
618	    });
619	  }
620	
621	  // Hamburger
622	  const hamburgerBtn = $("#hamburger-btn");
623	  if (hamburgerBtn) {
624	    hamburgerBtn.addEventListener("click", toggleSidebar);
625	  }
626	
627	  const sidebarBackdrop = $("#sidebar-backdrop");
628	  if (sidebarBackdrop) {
629	    sidebarBackdrop.addEventListener("click", () => toggleSidebar(false));
630	  }
631	
632	  // Keyboard shortcuts
633	  document.addEventListener("keydown", (e) => {
634	    // Don't intercept when typing in inputs
635	    if (e.target.tagName === "INPUT" || e.target.tagName === "TEXTAREA" || e.target.tagName === "SELECT") {
636	      if (e.key === "Escape") {
637	        e.target.blur();
638	      }
639	      return;
640	    }
641	
642	    switch (e.key.toLowerCase()) {
643	      case "r":
644	        e.preventDefault();
645	        forceRefresh();
646	        break;
647	      case "f":
648	        e.preventDefault();
649	        const si = $("#search-input");
650	        if (si) si.focus();
651	        break;
652	      case "1":
653	        e.preventDefault();
654	        setSentimentFilter("all");
655	        break;
656	      case "2":
657	        e.preventDefault();
658	        setSentimentFilter("bullish");
659	        break;
660	      case "3":
661	        e.preventDefault();
662	        setSentimentFilter("bearish");
663	        break;
664	      case "4":
665	        e.preventDefault();
666	        setSentimentFilter("neutral");
667	        break;
668	      case "escape":
669	        if (state.modalOpen) toggleModal(false);
670	        if (state.sidebarOpen) toggleSidebar(false);
671	        break;
672	    }
673	  });
674	
675	  // Copy API URL
676	  const apiUrlEl = $("#api-url");
677	  if (apiUrlEl) {
678	    apiUrlEl.addEventListener("click", () => {
679	      const url = `${API}/news`;
680	      if (navigator.clipboard) {
681	        navigator.clipboard.writeText(url).then(() => {
682	          apiUrlEl.textContent = "Copied!";
683	          setTimeout(() => {
684	            apiUrlEl.textContent = `${API}/news`;
685	          }, 1500);
686	        });
687	      }
688	    });
689	  }
690	}
