692	function setSentimentFilter(value) {
693	  state.filter.sentiment = value;
694	  $$(".sentiment-filter-btn").forEach((b) => {
695	    b.classList.toggle("active", b.dataset.sentiment === value);
696	  });
697	  renderNews();
698	}
