700	function toggleSidebar(forceState) {
701	  const open = typeof forceState === "boolean" ? forceState : !state.sidebarOpen;
702	  state.sidebarOpen = open;
703	  const sidebar = $(".sidebar");
704	  const backdrop = $("#sidebar-backdrop");
705	  if (sidebar) sidebar.classList.toggle("open", open);
706	  if (backdrop) backdrop.classList.toggle("open", open);
707	}
