709	function toggleModal(open) {
710	  state.modalOpen = open;
711	  const overlay = $("#modal-overlay");
712	  if (overlay) overlay.classList.toggle("open", open);
713	  // Populate API base URL in docs
714	  if (open) {
715	    $$(".api-base-url").forEach((el) => {
716	      el.textContent = window.location.origin + window.location.pathname.replace(/\/[^/]*$/, "");
717	    });
718	  }
