722	// Initialize
723	// ---------------------------------------------------------------------------
724	
725	// ---------------------------------------------------------------------------
726	// Auth UI
727	// ---------------------------------------------------------------------------
728	
729	function initAuth() {
730	  if (typeof SignalAuth === "undefined") return;
731	
732	  SignalAuth.init();
733	
734	  // Sign in button
735	  const btnSignin = $("#btn-signin");
736	  if (btnSignin) {
737	    btnSignin.addEventListener("click", () => {
738	      SignalAuth.showAuthModal("signin");
739	    });
740	  }
741	
742	  // Sign out button
743	  const btnSignout = $("#btn-signout");
744	  if (btnSignout) {
745	    btnSignout.addEventListener("click", () => {
746	      SignalAuth.signOut();
747	    });
748	  }
749	
750	  // User menu toggle
751	  const btnUser = $("#btn-user");
752	  const dropdown = $("#user-dropdown");
753	  if (btnUser && dropdown) {
754	    btnUser.addEventListener("click", (e) => {
755	      e.stopPropagation();
756	      dropdown.classList.toggle("open");
757	    });
758	    document.addEventListener("click", () => {
759	      dropdown.classList.remove("open");
760	    });
761	  }
762	
763	  // Listen for auth state changes
764	  SignalAuth.onAuthChange((user) => {
765	    updateAuthUI(user);
766	  });
767	}
768	
769	function updateAuthUI(user) {
770	  const btnSignin = $("#btn-signin");
771	  const userMenu = $("#user-menu");
772	
773	  if (user) {
774	    // Signed in
775	    if (btnSignin) btnSignin.style.display = "none";
776	    if (userMenu) userMenu.style.display = "flex";
777	
778	    const avatar = $("#user-avatar");
779	    const userName = $("#user-name");
780	    const dropdownEmail = $("#dropdown-email");
781	
782	    if (avatar && user.photoURL) {
783	      avatar.src = user.photoURL;
784	      avatar.alt = user.displayName || "";
785	    }
786	    if (userName) userName.textContent = user.displayName || user.email || "";
787	    if (dropdownEmail) dropdownEmail.textContent = user.email || "";
788	
789	    // Fetch tier info
790	    fetchTier();
791	  } else {
792	    // Signed out — block terminal for unauthenticated visitors
793	    if (btnSignin) btnSignin.style.display = "flex";
794	    if (userMenu) userMenu.style.display = "none";
795	    showUpgradeGate();
796	  }
797	}
798	
799	async function fetchTier() {
800	  try {
801	    const res = await SignalAuth.fetch(`${API}/auth/tier`);
802	    if (!res.ok) return;
803	    const data = await res.json();
804	    const rawTier = data.tier || "free";
805	    const tier = rawTier === "plus" ? "pro" : rawTier;
806	
807	    const badge = $("#tier-badge");
808	    const dropdownTier = $("#dropdown-tier");
809	
810	    if (badge) {
811	      badge.textContent = tier.toUpperCase();
812	      badge.className = "tier-badge" + (tier !== "free" ? " " + tier : "");
813	    }
814	    if (dropdownTier) {
815	      const labels = { free: "Free Plan", pro: "Pro Plan", plus: "Pro Plan" };
816	      dropdownTier.textContent = labels[tier] || "Free Plan";
817	    }
818	
819	    // Client-side terminal access gate (defense in depth)
820	    const features = data.features || {};
821	    if (features.terminal_access === false || tier === "free") {
822	      showUpgradeGate();
823	    } else {
824	      hideUpgradeGate();
825	    }
826	  } catch {
827	    // silent
828	  }
829	}
830	
831	/**
832	 * Show a full-screen overlay blocking the terminal for Free-tier users.
833	 * This is a client-side safety net; the server-side redirect is the
834	 * primary gate.
835	 */
836	function showUpgradeGate() {
837	  // Avoid creating duplicate overlays
838	  if ($("#upgrade-gate")) return;
839	
840	  const overlay = document.createElement("div");
841	  overlay.id = "upgrade-gate";
842	  overlay.style.cssText =
843	    "position:fixed;inset:0;z-index:10000;display:flex;align-items:center;" +
844	    "justify-content:center;background:rgba(1,4,9,0.95);";
845	  overlay.innerHTML =
846	    '<div style="text-align:center;max-width:420px;padding:40px;' +
847	    'border:1px solid rgba(48,54,61,0.8);border-radius:12px;background:#0d1117;">' +
848	    '<h2 style="color:#e6edf3;margin:0 0 12px;font-size:22px;">Upgrade to Pro</h2>' +
849	    '<p style="color:#8b949e;margin:0 0 24px;line-height:1.6;">' +
850	    "The SIGNAL terminal requires a Pro subscription. " +
851	    "Get full access to real-time news, sentiment analysis, and deduplication." +
852	    "</p>" +
853	    '<a href="/pricing" style="display:inline-block;padding:10px 28px;' +
854	    "background:#238636;color:#fff;border-radius:6px;text-decoration:none;" +
855	    'font-weight:600;font-size:14px;">View Plans</a>' +
856	    '<div style="margin-top:16px;">' +
857	    '<a href="/" style="color:#8b949e;font-size:13px;text-decoration:underline;">Back to home</a>' +
858	    "</div></div>";
859	
860	  document.body.appendChild(overlay);
861	
862	  // Stop auto-refresh to avoid unnecessary API calls
863	  stopAutoRefresh();
864	}
865	
866	function hideUpgradeGate() {
867	  const overlay = $("#upgrade-gate");
868	  if (overlay) overlay.remove();
869	}
870	
871	
872	function init() {
873	  renderSkeleton();
874	  renderSources();
875	  bindEvents();
876	  updateClock();
877	  initAuth();
878	
879	  // Start clock
880	  setInterval(updateClock, 1000);
881	
882	  // Initial fetch
883	  fetchNews();
884	  fetchStats();
885	  fetchSources();
886	
887	  // Start auto-refresh
888	  startAutoRefresh();
889	
890	  // Periodic stats refresh (every 30s)
891	  setInterval(() => {
892	    fetchStats();
893	    fetchSources();
894	  }, 30000);
895	}
896	
897	// Start when DOM is ready
898	if (document.readyState === "loading") {
899	  document.addEventListener("DOMContentLoaded", init);
900	} else {
901	  init();
902	}
