818	function _switchTab(tab) {
819	  var tabs = document.querySelectorAll("#sa-tabs .sa-tab");
820	  tabs.forEach(function (t) { t.classList.toggle("active", t.dataset.tab === tab); });
821	
822	  var tabsBar = document.getElementById("sa-tabs");
823	  var panels = document.querySelectorAll(".sa-panel");
824	  panels.forEach(function (p) { p.classList.remove("active"); });
825	
826	  if (tab === "forgot" || tab === "reset") {
827	    tabsBar.style.display = "none";
828	    document.getElementById("sa-panel-" + tab).classList.add("active");
829	    document.getElementById("sa-footer-signin").style.display = "none";
830	    document.getElementById("sa-footer-signup").style.display = "none";
831	  } else {
832	    tabsBar.style.display = "flex";
833	    document.getElementById("sa-panel-" + tab).classList.add("active");
834	    document.getElementById("sa-footer-signin").style.display = tab === "signin" ? "block" : "none";
835	    document.getElementById("sa-footer-signup").style.display = tab === "signup" ? "block" : "none";
836	  }
837	  _clearMessages();
838	}
