:root {
  /* Backgrounds */
  --bg-primary: #0d1117;
  --bg-surface: #161b22;
  --bg-surface-2: #1c2128;
  --bg-surface-3: #21262d;
  --bg-hover: rgba(177, 186, 196, 0.06);
  --bg-active: rgba(177, 186, 196, 0.1);

  /* Borders */
  --border: #30363d;
  --border-muted: #21262d;
  --border-emphasis: #484f58;

  /* Text */
  --text-primary: #e6edf3;
  --text-secondary: #8b949e;
  --text-muted: #6e7681;
  --text-faint: #484f58;

  /* Semantic */
  --green: #3fb950;
  --green-bg: rgba(63, 185, 80, 0.1);
  --green-border: rgba(63, 185, 80, 0.3);
  --red: #f85149;
  --red-bg: rgba(248, 81, 73, 0.1);
