}

.detail-headline {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  line-height: 1.5;
  margin: 0 0 var(--sp-2);
}

.detail-meta {
  display: flex;
  align-items: center;
  gap: var(--sp-2);
  font-size: 12px;
  color: var(--text-muted);
}

.detail-time {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
}

/* Ticker header */
.detail-ticker-header {
  display: flex;
  align-items: center;
  gap: var(--sp-3);
  margin-bottom: var(--sp-4);
}

.detail-ticker-symbol {
  font-family: 'JetBrains Mono', monospace;
  font-size: 28px;
  font-weight: 700;
  color: var(--blue);
  letter-spacing: 1px;
}

.detail-asset-type {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  color: var(--text-muted);
  padding: 2px 8px;
  background: var(--bg-surface-2);
  border: 1px solid var(--border-muted);
  border-radius: var(--radius-sm);
  text-transform: uppercase;
}

/* Metrics grid */
.detail-metrics {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--sp-3);
  margin-bottom: var(--sp-4);
}

.detail-metric {
  padding: var(--sp-3);
  background: var(--bg-surface-2);
  border: 1px solid var(--border-muted);
  border-radius: var(--radius-md);
}

.detail-metric-label {
  font-size: 10px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: var(--sp-1);
}

.detail-metric-value {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  display: flex;
  align-items: center;
  gap: var(--sp-2);
}

.detail-metric-sub {
  font-size: 12px;
  font-weight: 400;
  color: var(--text-secondary);
}

.detail-confidence {
  font-family: 'JetBrains Mono', monospace;
  font-size: 20px;
  color: var(--blue);
}

