.detail-risk {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: var(--radius-sm);
}

.detail-risk.green {
  color: var(--green);
  background: var(--green-bg);
}

.detail-risk.yellow {
  color: var(--yellow);
  background: var(--yellow-bg);
}

.detail-risk.red {
  color: var(--red);
  background: var(--red-bg);
}

/* Tradeable badge */
.detail-tradeable {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: var(--radius-sm);
}

.detail-tradeable.yes {
  color: var(--green);
  background: var(--green-bg);
}

.detail-tradeable.no {
  color: var(--red);
  background: var(--red-bg);
}

/* Reasoning section */
.detail-reasoning {
  border-top: 1px solid var(--border-muted);
  padding-top: var(--sp-3);
}

.detail-reasoning-label {
  font-size: 10px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: var(--sp-2);
}

.detail-reasoning-text {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.7;
  max-height: 200px;
  overflow-y: auto;
  overscroll-behavior: contain;
  white-space: pre-wrap;
}

/* Upgrade prompt (non-Max users) */
.detail-upgrade {
  text-align: center;
  padding: var(--sp-6) var(--sp-4);
}

.detail-upgrade-icon {
  font-size: 32px;
  color: var(--text-muted);
  margin-bottom: var(--sp-3);
}

.detail-upgrade h4 {
  font-size: 16px;
  font-weight: 600;
  color: var(--text-primary);
  margin: 0 0 var(--sp-2);
}

.detail-upgrade p {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.6;
  margin: 0 0 var(--sp-4);
}

.detail-upgrade-btn {
